def safe_api_call(url: str, method: str, allowlist: list[str], responses: dict[str, str]) -> str:
    def is_https(url: str) -> bool:
        return url.startswith("https://")

    def is_allowlisted(url: str, allowlist: list[str]) -> bool:
        for allowed_url in allowlist:
            if url.startswith(allowed_url):
                return True
        return False

    def is_valid_method(method: str) -> bool:
        return method.upper() == "GET"

    def is_valid_host(url: str) -> bool:
        # Check for localhost or private IPs
        if "localhost" in url or "127.0.0.1" in url:
            return False
        # Check for bare IPs
        if url.startswith("https://") and url[8:].replace('.', '').isdigit():
            return False
        return True

    if not is_https(url):
        return "Error: Only HTTPS scheme is allowed."
    if not is_valid_method(method):
        return "Error: Only GET method is allowed."
    if not is_allowlisted(url, allowlist):
        return "Error: URL is not allowlisted."
    if not is_valid_host(url):
        return "Error: Invalid host."

    response_key = f"{method.upper()} {url}"
    return responses.get(response_key, "Error: No response available for the given URL and method.")

